import 'package:bookly/Core/Utils/Errors/failure.dart';import 'package:bookly/Core/network/dio.dart';import '../../data/repositories/home_repo.dart';import 'package:dartz/dartz.dart';import 'package:dio/dio.dart';import 'package:flutter/foundation.dart'; // import needed for compute functionimport '../../../../Core/Models/book_model.dart';import '../entities/book_entities.dart';class HomeRepoImpl implements HomeRepo {  final Map<String, List<BookEntities>> _cache = {};  @override  Future<Either<Failure, List<BookEntities>>> fetchBooksPictures() async {    return _fetchBooks(path: 'volumes?Sorting=newest&Filtering=full&q=Novels');  }  @override  Future<Either<Failure, List<BookEntities>>> fetchAllBooks() async {    return _fetchBooks(        path:            'volumes?Sorting=newest&q=computer science');  }  @override  Future<Either<Failure, List<BookEntities>>> fetchSimilarBooks(      {required String category}) async {    return _fetchBooks(        path: 'volumes?Sorting=newest&q=computer science');  }  Future<Either<Failure, List<BookEntities>>> _fetchBooks(      {required String path}) async {    if (_cache.containsKey(path)) {      return right(_cache[path]!);    }    try {      var response = await DioHelper.getData(          path: path,          );      var data = response.data['items'] as List;      List<BookModel> books = await compute(parseBooks, data);      _cache[path] = books;      return right(books);    } catch (e) {      if (e is DioException) {        if (e.response?.statusCode == 429) {          return left(              ServerFailure('Too many requests. Please try again later.'));        }        return left(ServerFailure.fromDioError(e));      } else {        return left(ServerFailure.fromResponse(e.hashCode, e));      }    }  }}// Function to parse books in a separate isolateList<BookModel> parseBooks(List data) {  return data.map((item) => BookModel.fromJson(item)).toList();}